import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Badge, Input } from 'decantr/components';

code.example:
function DocumentVault({ documents, folders }) {
  const { div, h1, h2, span, ul, li } = tags;
  const [currentFolder, setCurrentFolder] = createSignal('all');
  const [search, setSearch] = createSignal('');
  const [view, setView] = createSignal('list');
  const [selectedDoc, setSelectedDoc] = createSignal(null);

  const categories = [
    { id: 'all', name: 'All Documents', icon: 'folder' },
    { id: 'leases', name: 'Leases', icon: 'file-text' },
    { id: 'deeds', name: 'Deeds & Titles', icon: 'home' },
    { id: 'insurance', name: 'Insurance', icon: 'shield' },
    { id: 'tax', name: 'Tax Documents', icon: 'file-digit' },
    { id: 'inspections', name: 'Inspections', icon: 'clipboard-check' },
    { id: 'contracts', name: 'Vendor Contracts', icon: 'file-signature' },
    { id: 'applications', name: 'Applications', icon: 'user-plus' },
    { id: 'legal', name: 'Legal', icon: 'scale' }
  ];

  const filtered = () => documents.filter(d => {
    if (currentFolder() !== 'all' && d.category !== currentFolder()) return false;
    if (search() && !d.name.toLowerCase().includes(search().toLowerCase())) return false;
    return true;
  });

  const expiringSoon = documents.filter(d => d.expiresAt && new Date(d.expiresAt) < new Date(Date.now() + 30 * 24 * 60 * 60 * 1000));

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Documents'),
      div({ class: css('_flex _gap2') },
        div({ class: css('_flex _r1 _border _overflow[hidden]') },
          Button({ variant: view() === 'list' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('list') }, icon('list')),
          Button({ variant: view() === 'grid' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('grid') }, icon('grid'))
        ),
        Button({ variant: 'primary' }, icon('upload'), 'Upload')
      )
    ),
    expiringSoon.length > 0 ? div({ class: css('_p3 _bgWarning/10 _r2 _flex _aic _gap2') },
      icon('alert-triangle', { class: css('_fgwarning') }),
      span({ class: css('_textsm') }, `${expiringSoon.length} document(s) expiring soon`),
      Button({ variant: 'ghost', size: 'sm' }, 'View')
    ) : null,
    div({ class: css('_flex _gap6') },
      div({ class: css('_w56 _shrink0') },
        Input({ type: 'search', placeholder: 'Search documents...', value: search(), oninput: e => setSearch(e.target.value), class: css('_mb4') }),
        ul({ class: css('_flex _col _gap1') },
          ...categories.map(cat =>
            li({},
              Button({
                variant: currentFolder() === cat.id ? 'default' : 'ghost',
                class: css('_wfull _jcs'),
                onclick: () => setCurrentFolder(cat.id)
              },
                icon(cat.icon, { size: '16' }),
                span({ class: css('_flex1 _textleft _ml2') }, cat.name),
                span({ class: css('_textsm _fgmuted') }, documents.filter(d => cat.id === 'all' || d.category === cat.id).length)
              )
            )
          )
        )
      ),
      div({ class: css('_flex1') },
        view() === 'list' ? DocumentList({ documents: filtered(), onSelect: setSelectedDoc }) : DocumentGrid({ documents: filtered(), onSelect: setSelectedDoc })
      ),
      selectedDoc() ? div({ class: css('_w80 _shrink0 estate-card _p4') },
        DocumentPreview({ document: selectedDoc(), onClose: () => setSelectedDoc(null) })
      ) : null
    )
  );
}

function DocumentList({ documents, onSelect }) {
  const { div, span, table, thead, tbody, tr, th, td } = tags;

  return div({ class: css('estate-table _overflow[auto]') },
    table({ class: css('_wfull') },
      thead({},
        tr({ class: css('_bgSurface') },
          th({ class: css('_p3 _textleft _font500') }, 'Name'),
          th({ class: css('_p3 _textleft _font500') }, 'Property'),
          th({ class: css('_p3 _textleft _font500') }, 'Category'),
          th({ class: css('_p3 _textleft _font500') }, 'Uploaded'),
          th({ class: css('_p3 _textleft _font500') }, 'Expires'),
          th({ class: css('_p3') })
        )
      ),
      tbody({},
        ...documents.map((d, i) => {
          const isExpiring = d.expiresAt && new Date(d.expiresAt) < new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
          return tr({ class: css(`${i % 2 === 0 ? '' : '_bgSurfaceRaised'} _cursor[pointer] _hoverBg`), onclick: () => onSelect(d) },
            td({ class: css('_p3') },
              div({ class: css('_flex _aic _gap2') },
                icon(getFileIcon(d.type), { size: '16', class: css('_fgmuted') }),
                span({ class: css('_font500') }, d.name)
              )
            ),
            td({ class: css('_p3 _textsm') }, d.propertyName || '—'),
            td({ class: css('_p3') }, Badge({ variant: 'outline' }, d.category)),
            td({ class: css('_p3 _textsm') }, new Date(d.uploadedAt).toLocaleDateString()),
            td({ class: css('_p3 _textsm') },
              d.expiresAt ? span({ class: css(isExpiring ? '_fgwarning' : '') }, new Date(d.expiresAt).toLocaleDateString()) : '—'
            ),
            td({ class: css('_p3') },
              div({ class: css('_flex _gap1') },
                Button({ variant: 'ghost', size: 'sm', onclick: e => { e.stopPropagation(); window.open(d.url); } }, icon('download', { size: '14' })),
                Button({ variant: 'ghost', size: 'sm' }, icon('more-vertical', { size: '14' }))
              )
            )
          );
        })
      )
    )
  );
}

function getFileIcon(type) {
  const icons = { pdf: 'file-text', image: 'image', doc: 'file-text', spreadsheet: 'file-spreadsheet' };
  return icons[type] || 'file';
}

