function DocumentGrid({ documents, onSelect }) {
  const { div, span, img } = tags;

  return div({ class: css('_grid _cols4 _gap4') },
    ...documents.map(d =>
      div({ class: css('estate-card _p3 _cursor[pointer] _hoverShadow _trans'), onclick: () => onSelect(d) },
        div({ class: css('_h24 _bgSurfaceRaised _r1 _flex _aic _jcc _mb3') },
          d.thumbnail ? img({ src: d.thumbnail, class: css('_wfull _hfull _objcover _r1') }) : icon(getFileIcon(d.type), { size: '32', class: css('_fgmuted') })
        ),
        span({ class: css('_textsm _font500 _block _truncate') }, d.name),
        span({ class: css('_textxs _fgmuted') }, new Date(d.uploadedAt).toLocaleDateString())
      )
    )
  );
}

