function TenantDocuments({ documents }) {
  const { div, h1, span } = tags;

  return div({ class: css('_flex _col _gap4') },
    h1({ class: css('_heading4') }, 'Your Documents'),
    div({ class: css('_flex _col _gap2') },
      ...documents.map(d =>
        div({ class: css('estate-card _p4 _flex _aic _gap4') },
          icon(getFileIcon(d.type), { size: '24', class: css('_fgmuted') }),
          div({ class: css('_flex1') },
            span({ class: css('_font500 _block') }, d.name),
            span({ class: css('_textsm _fgmuted') }, d.category)
          ),
          Button({ variant: 'outline', size: 'sm', onclick: () => window.open(d.url) }, icon('download'), 'Download')
        )
      )
    )
  );
}

